import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router } from '@angular/router';
import { forkJoin } from 'rxjs';
import { MatCardModule } from '@angular/material/card';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatDialog } from '@angular/material/dialog';
import { MatSnackBar } from '@angular/material/snack-bar';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
import { CustomerService } from '../../core/services/customer.service';
import { AccountService } from '../../core/services/account.service';
import { Customer } from '../../core/models/customer.model';
import { Account, AccountType } from '../../core/models/account.model';
import { AccountCardComponent } from './account-card/account-card.component';
import { ConfirmDialogComponent } from '../../shared/components/confirm-dialog/confirm-dialog.component';

@Component({
  selector: 'app-customer-detail',
  standalone: true,
  imports: [
    CommonModule, MatCardModule, MatButtonModule, MatIconModule,
    MatProgressSpinnerModule, AccountCardComponent,
  ],
  templateUrl: './customer-detail.component.html',
})
export class CustomerDetailComponent implements OnInit {
  customer?: Customer;
  accounts: Account[] = [];
  loading = true;
  error = '';
  customerId!: number;

  newAccountLoading = false;

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private customerService: CustomerService,
    private accountService: AccountService,
    private dialog: MatDialog,
    private snackBar: MatSnackBar,
  ) {}

  ngOnInit(): void {
    this.customerId = Number(this.route.snapshot.paramMap.get('id'));
    this.loadAll();
  }

  loadAll(): void {
    this.loading = true;
    this.error = '';
    forkJoin({
      customer: this.customerService.getById(this.customerId),
      accounts: this.accountService.getByCustomer(this.customerId),
    }).subscribe({
      next: ({ customer, accounts }) => {
        this.customer = customer;
        this.accounts = accounts;
        this.loading = false;
      },
      error: (err: Error) => {
        this.error = err.message;
        this.loading = false;
      },
    });
  }

  reloadAccounts(): void {
    this.accountService.getByCustomer(this.customerId).subscribe({
      next: (accounts) => (this.accounts = accounts),
    });
  }

  reloadCustomerAndAccounts(): void {
    forkJoin({
      customer: this.customerService.getById(this.customerId),
      accounts: this.accountService.getByCustomer(this.customerId),
    }).subscribe({
      next: ({ customer, accounts }) => {
        this.customer = customer;
        this.accounts = accounts;
      },
    });
  }

  openAddAccount(): void {
    const ref = this.dialog.open(ConfirmDialogComponent, {
      data: {
        title: 'Crear nueva cuenta',
        message: `¿Qué tipo de cuenta desea crear?<br><br>
          <strong>Ahorro (53XXXXXXXX)</strong> — saldo mínimo $0<br>
          <strong>Corriente (33XXXXXXXX)</strong> — puede tener sobregiro`,
        confirmLabel: 'Ahorro',
        cancelLabel: 'Corriente',
      },
      width: '400px',
    });
    ref.afterClosed().subscribe((result) => {
      if (result === undefined) return;
      const accountType: AccountType = result === true ? 'SAVINGS' : 'CHECKING';
      this.newAccountLoading = true;
      this.accountService.create({ accountType, customerId: this.customerId }).subscribe({
        next: (res) => {
          this.newAccountLoading = false;
          this.snackBar.open(res.message, 'Cerrar', { duration: 3000 });
          this.reloadAccounts();
        },
        error: (err: Error) => {
          this.newAccountLoading = false;
          this.snackBar.open(err.message, 'Cerrar', { duration: 5000, panelClass: 'snack-error' });
        },
      });
    });
  }

  goBack(): void {
    this.router.navigate(['/']);
  }

  get initials(): string {
    if (!this.customer) return '?';
    return `${this.customer.firstName[0]}${this.customer.lastName[0]}`.toUpperCase();
  }

  get totalBalance(): number {
    return this.accounts.reduce((sum, a) => sum + a.balance, 0);
  }

  get activeAccounts(): number {
    return this.accounts.filter(a => a.status === 'ACTIVE').length;
  }

  formatCurrency(value: number): string {
    return new Intl.NumberFormat('es-CO', {
      style: 'currency', currency: 'COP', minimumFractionDigits: 2,
    }).format(value);
  }

  formatDate(dateStr?: string): string {
    if (!dateStr) return '-';
    return new Date(dateStr).toLocaleDateString('es-CO', {
      day: '2-digit', month: 'long', year: 'numeric',
    });
  }

  calcAge(birthDate: string): number {
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
    return age;
  }

  idTypeLabels: { [key: string]: string | undefined } = {
    CC: 'Cédula de Ciudadanía',
    CE: 'Cédula de Extranjería',
    TI: 'Tarjeta de Identidad',
    PASSPORT: 'Pasaporte',
    NIT: 'NIT',
  };
}
<div class="page-container">

  <!-- Back -->
  <button class="back-link" (click)="goBack()">
    <mat-icon>arrow_back</mat-icon>
    Volver a clientes
  </button>

  <!-- Loading -->
  @if (loading) {
    <div class="loading-state">
      <mat-spinner diameter="24"></mat-spinner>
      <span>Cargando información del cliente...</span>
    </div>
  }

  <!-- Error -->
  @if (error) {
    <div class="error-state">
      <mat-icon>error_outline</mat-icon>
      {{ error }}
    </div>
  }

  @if (!loading && !error && customer) {
    <!-- Customer Header Card -->
    <mat-card class="customer-header-card">
      <mat-card-content>
        <!-- Top row: avatar + name + balance -->
        <div class="customer-top-row">
          <div class="customer-avatar">{{ initials }}</div>
          <div class="customer-name-block">
            <h1>{{ customer.firstName }} {{ customer.lastName }}</h1>
            <p class="client-id">
              <span class="id-type-label">{{ idTypeLabels[customer.identificationType] ?? customer.identificationType }}</span>
              {{ customer.identificationNumber }}
            </p>
          </div>
          <div class="total-balance-block">
            <p class="balance-label">Saldo total en cuentas</p>
            <p class="balance-amount">{{ formatCurrency(totalBalance) }}</p>
          </div>
        </div>

        <!-- Divider -->
        <div class="header-divider"></div>

        <!-- Info grid -->
        <div class="customer-info-grid">
          <div class="customer-info-item">
            <div class="info-label">
              <mat-icon>email</mat-icon>
              Correo electrónico
            </div>
            <div class="info-value">{{ customer.email }}</div>
          </div>
          <div class="customer-info-item">
            <div class="info-label">
              <mat-icon>cake</mat-icon>
              Fecha de nacimiento
            </div>
            <div class="info-value">{{ formatDate(customer.birthDate) }} · {{ calcAge(customer.birthDate) }} años</div>
          </div>
          <div class="customer-info-item">
            <div class="info-label">
              <mat-icon>account_balance</mat-icon>
              Cuentas
            </div>
            <div class="info-value">
              {{ accounts.length }} total ·
              <span style="color:#16a34a;font-weight:600">{{ activeAccounts }} activa{{ activeAccounts !== 1 ? 's' : '' }}</span>
            </div>
          </div>
          <div class="customer-info-item">
            <div class="info-label">
              <mat-icon>tag</mat-icon>
              ID Cliente
            </div>
            <div class="info-value" style="font-family:monospace">#{{ customer.id }}</div>
          </div>
        </div>
      </mat-card-content>
    </mat-card>

    <!-- Accounts Section -->
    <div class="accounts-section">
      <div class="section-header">
        <div class="section-title">
          <mat-icon>account_balance</mat-icon>
          <h2>Cuentas</h2>
          <span class="count-badge">{{ accounts.length }}</span>
        </div>
        <button mat-flat-button color="primary" (click)="openAddAccount()" [disabled]="newAccountLoading">
          @if (newAccountLoading) {
            <mat-spinner diameter="16" style="display:inline-block;margin-right:8px"></mat-spinner>
          }
          <mat-icon>add</mat-icon>
          Nueva cuenta
        </button>
      </div>

      @if (accounts.length === 0) {
        <div class="empty-accounts">
          <mat-icon>account_balance</mat-icon>
          <p>Este cliente no tiene cuentas registradas</p>
          <button mat-stroked-button color="primary" (click)="openAddAccount()">
            <mat-icon>add</mat-icon> Crear primera cuenta
          </button>
        </div>
      }

      @for (account of accounts; track account.id) {
        <app-account-card
          [account]="account"
          [customerId]="customerId"
          (accountDeleted)="reloadAccounts()"
          (balanceUpdated)="reloadCustomerAndAccounts()">
        </app-account-card>
      }
    </div>
  }
</div>
